theory.good_example:
import sqlite3
from flask import request, abort

@app.route("/user")
def get_user():
    name = request.args.get("name")
    if not name:
        abort(400)
    query = "SELECT * FROM users WHERE name = ?"
    conn = sqlite3.connect("app.db")
    cur = conn.cursor()
    cur.execute(query, (name,))  # безопасно: данные отдельно от текста запроса
    rows = cur.fetchall()
    return str(rows)
